"""素朴な in-process キャッシュ。あちこちから直接触られている。"""
_cache: dict = {}


def get(key):
    return _cache.get(key)


def put(key, value):
    _cache[key] = value


def invalidate(key=None):
    # 呼び出し側ごとに key 指定だったり全消しだったりで一貫性がない
    if key is None:
        _cache.clear()
    else:
        _cache.pop(key, None)
